// Closes `Section` to downstream impls while keeping the public trait usable as
// a bound.
mod sealed {
    #[allow(
        unnameable_types,
        reason = "sealing Section means Sealed is reachable (as its supertrait) but deliberately not nameable downstream"
    )]
    pub trait Sealed {}
}

