/// Decode a verified section body using the contract selected by `type_id`.
///
/// # Errors
///
/// Returns [`CodecError`] for unknown `type_id`, schema mismatch, caps, or
/// Parquet decode failures.
pub fn decode_any(type_id: u32, section: VerifiedSection) -> Result<DecodedSection, CodecError> {
    let contract = registry()
        .iter()
        .find(|contract| contract.type_id.get() == type_id)
        .ok_or(CodecError::UnknownType { type_id })?;
    let bytes_in = section.len();
    decode_batches(contract, section).map_err(|source| CodecError::Section {
        type_id,
        bytes_in,
        source: Box::new(source),
    })
}

/// Decode a section read into a pooled buffer.
///
/// # Errors
///
/// Returns [`CodecError`] when length, CRC, type lookup, or decoding fails.
pub fn decode_pooled(
    pool: &BytesPool,
    type_id: u32,
    expected_len: usize,
    expected_crc: u32,
    crc32c: impl FnOnce(&[u8]) -> u32,
    fill: impl FnOnce(&mut Vec<u8>),
) -> Result<DecodedSection, CodecError> {
    if expected_len > MAX_SECTION_BYTES {
        return Err(CodecError::SectionTooLarge {
            len: expected_len,
            max: MAX_SECTION_BYTES,
        });
    }
    let bytes = pool.load(fill);
    // Guard against a buggy fill that writes more than the caller announced.
    if bytes.len() > MAX_SECTION_BYTES {
        return Err(CodecError::SectionTooLarge {
            len: bytes.len(),
            max: MAX_SECTION_BYTES,
        });
    }
    let bytes_in = bytes.len();
    let section = VerifiedSection::verify(bytes, expected_crc, crc32c).map_err(|source| {
        CodecError::Section {
            type_id,
            bytes_in,
            source: Box::new(source),
        }
    })?;
    decode_any(type_id, section)
}

/// Run the registry linter over every known type.
///
/// # Errors
///
/// Returns all linter errors found in registered contracts.
pub fn lint_registry() -> Result<(), Vec<LintError>> {
    lint(registry())?;
    lint_references(registry())
}

#[cfg(test)]
mod tests {
    use arrow_array::ArrayRef;
    use arrow_array::array::new_empty_array;
    use bytes::Bytes;

    use super::{
        BytesPool, CodecError, DICT_BLOBS_TYPE_ID, DICT_STRINGS_TYPE_ID, VerifiedSection,
        arrow_schema, decode_any, decode_pooled, encode_section, lint_registry, registry,
        section_name,
    };

    #[test]
    fn the_registry_is_clean() {
        assert_eq!(lint_registry(), Ok(()));
    }

    #[test]
    fn registry_is_not_empty() {
        assert!(!registry().is_empty());
    }

    /// Registry wiring check with no per-type branch.
    #[test]
    fn every_registered_type_decodes_an_empty_section() {
        for contract in registry() {
            let schema = arrow_schema(contract);
            let columns: Vec<ArrayRef> = schema
                .fields()
                .iter()
                .map(|field| new_empty_array(field.data_type()))
                .collect();
            let bytes = encode_section(contract, columns).expect("encode empty section");
            let bytes_in = bytes.len();
            let id = contract.type_id.get();
            let decoded =
                decode_any(id, VerifiedSection::for_test(bytes.into())).expect("decode_any");
            assert_eq!(decoded.stats.type_id, id, "stats carries the type_id");
            assert_eq!(
                decoded.stats.rows, 0,
                "type {id} decoded a non-empty section"
            );
            assert_eq!(
                decoded.stats.bytes_in, bytes_in,
                "stats.bytes_in matches input"
            );
        }
    }

    #[test]
    fn decode_pooled_reads_into_a_pooled_buffer_and_decodes() {
        let pool = BytesPool::new(2, 1 << 20);
        let contract = &registry()[0];
        let id = contract.type_id.get();
        let columns: Vec<ArrayRef> = arrow_schema(contract)
            .fields()
            .iter()
            .map(|field| new_empty_array(field.data_type()))
            .collect();
        let encoded = encode_section(contract, columns).expect("encode empty section");
        // Stand-in CRC = byte length; production code passes kronika-format's.
        let crc = |b: &[u8]| u32::try_from(b.len()).unwrap_or(u32::MAX);
        let expected = crc(&encoded);
        let decoded = decode_pooled(&pool, id, encoded.len(), expected, crc, |buf| {
            buf.extend_from_slice(&encoded);
        })
        .expect("decode_pooled");
        assert_eq!(decoded.stats.type_id, id);
    }

    #[test]
    fn decode_any_rejects_an_unregistered_type() {
        // Structurally valid (class 2, source 999, version 999) but not in the
        // registry, so decode_any must reject it rather than decode garbage.
        assert!(matches!(
            decode_any(2_999_999, VerifiedSection::for_test(Bytes::new())),
            Err(CodecError::UnknownType { type_id: 2_999_999 })
        ));
    }

    #[test]
    fn section_name_uses_registry_contracts_and_dictionary_names() {
        assert_eq!(section_name(1_004_001), Some("pg_store_plans_vadv"));
        assert_eq!(section_name(1_019_001), Some("pg_settings"));
        assert_eq!(section_name(DICT_STRINGS_TYPE_ID), Some("dict.strings"));
        assert_eq!(section_name(DICT_BLOBS_TYPE_ID), Some("dict.blobs"));
        assert_eq!(section_name(9_999_999), None);
    }
}
